#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
JLPT Anki Thai — N5 ถึง N1 ในไฟล์เดียว

อัปโหลดไฟล์นี้ขึ้น GitHub โดยเปลี่ยนชื่อเป็น build_decks.py
จากนั้นกด Actions → Run workflow

N5/N4/N3 ฝังข้อมูลอยู่ในไฟล์แล้ว
N2/N1 ดึงข้อมูลจาก JLPT Sensei ตอนรัน
"""

from __future__ import annotations
import argparse, base64, csv, html, importlib, json, re, subprocess, sys, urllib.request, zlib
from pathlib import Path
from typing import Any

def ensure_package(import_name: str, pip_name: str | None = None) -> None:
    try:
        importlib.import_module(import_name)
    except ImportError:
        subprocess.check_call([sys.executable, "-m", "pip", "install", pip_name or import_name, "-q"])

ensure_package("genanki")
ensure_package("bs4", "beautifulsoup4")

import genanki
from bs4 import BeautifulSoup

ROOT = Path(__file__).resolve().parent
APKG_DIR = ROOT / "export_apkg"
CSV_DIR = ROOT / "export_csv"
APKG_DIR.mkdir(exist_ok=True)
CSV_DIR.mkdir(exist_ok=True)

EMBEDDED = {"N5":"","N4":"","N3":""}

CONFIG = {
"N5":{"color":"#4CAF50","model_id":2061005001,"deck_id":2061005002,"title":"JLPT N5 Kanji Thai"},
"N4":{"color":"#1976D2","model_id":2061004001,"deck_id":2061004002,"title":"JLPT N4 Kanji Thai - Additional"},
"N3":{"color":"#F9A825","model_id":2061003001,"deck_id":2061003002,"title":"JLPT N3 Kanji Thai - Additional"},
"N2":{"color":"#EF6C00","model_id":2061002001,"deck_id":2061002002,"title":"JLPT N2 Kanji Thai - Additional","expected":374,"pages":4,"url":"https://jlptsensei.com/jlpt-n2-kanji-list/"},
"N1":{"color":"#C62828","model_id":2061001001,"deck_id":2061001002,"title":"JLPT N1 Kanji Thai - Additional","expected":1504,"pages":16,"url":"https://jlptsensei.com/jlpt-n1-kanji-list/"},
}

HEADERS={"User-Agent":"Mozilla/5.0 AppleWebKit/537.36 Chrome/120 Safari/537.36"}

def unpack(level):
    return json.loads(zlib.decompress(base64.b64decode(EMBEDDED[level])).decode("utf-8"))

def clean_reading(text):
    jp=re.findall(r"[ァ-ヶーぁ-ん一-龯・、()]+"," ".join(text.split()))
    return jp[-1].replace("、","・") if jp else "—"

def fetch_remote(level):
    cfg=CONFIG[level]
    rows=[]
    for page in range(1,cfg["pages"]+1):
        url=cfg["url"] if page==1 else f'{cfg["url"]}page/{page}/'
        req=urllib.request.Request(url,headers=HEADERS)
        with urllib.request.urlopen(req,timeout=45) as r:
            soup=BeautifulSoup(r.read().decode("utf-8","replace"),"html.parser")
        count=0
        for tr in soup.select("table tr"):
            cells=[c.get_text(" ",strip=True) for c in tr.select("th,td")]
            if len(cells)<5 or not cells[0].isdigit():
                continue
            k=cells[1].strip()
            if len(k)!=1:
                continue
            on,kun,meaning=clean_reading(cells[2]),clean_reading(cells[3]),cells[4].strip()
            reading=kun.split("・")[0] if kun!="—" else on.split("・")[0]
            rows.append({
                "kanji":k,"strokes":"?","on":on,"kun":kun,"meaning":meaning,
                "pos":"未分類","memory":f"เชื่อมรูปคันจิ {k} กับความหมาย “{meaning}”",
                "vocab":[{"word":k,"reading":reading,"pos":"未分類","meaning":meaning}],
                "examples":[{"jp":f"「{k}」という漢字を覚えます。","reading":f"「{k}」という かんじ を おぼえます。","th":f"จำคันจิ {k}"}]
            })
            count+=1
        print(f"{level} หน้า {page}: {count} ตัว")
    unique={}
    for item in rows:
        unique.setdefault(item["kanji"],item)
    data=list(unique.values())
    if len(data)!=cfg["expected"]:
        raise RuntimeError(f'{level} ควรได้ {cfg["expected"]} ตัว แต่ได้ {len(data)} ตัว')
    return data

def vocab_html(items):
    return "<br><br>".join(
        f"<b>{html.escape(str(x['word']))}</b>（{html.escape(str(x['reading']))}） "
        f"<span class='tag'>{html.escape(str(x['pos']))}</span><br>= {html.escape(str(x['meaning']))}"
        for x in items)

def examples_html(items):
    return "<br><br>".join(
        f"<b>{html.escape(str(x['jp']))}</b><br>（{html.escape(str(x['reading']))}）<br>= {html.escape(str(x['th']))}"
        for x in items)

def make_model(level):
    cfg=CONFIG[level]; color=cfg["color"]
    return genanki.Model(
        cfg["model_id"],f"JLPT {level} Kanji Thai Premium",
        fields=[{"name":n} for n in ["Kanji","Stroke","POS","On","Kun","Meaning","Memory","Vocab","Examples"]],
        templates=[{
            "name":"Kanji Card",
            "qfmt":f"<div class='kanji-box'>{{Kanji}}</div><div class='front-meta'>{{Stroke}}画 <span class='sep'>│</span> {{POS}}</div><div class='jlpt'>JLPT {level}</div>",
            "afmt":f"<div class='kanji-box small'>{{Kanji}}</div><div class='front-meta'>{{Stroke}}画 <span class='sep'>│</span> {{POS}}</div><div class='jlpt'>JLPT {level}</div><hr id='answer'><div class='body'><div class='head'>音読み</div>{{On}}<div class='head'>訓読み</div>{{Kun}}<div class='head'>ความหมาย</div>{{Meaning}}<div class='memory'><b>💡 วิธีจำ</b><br>{{Memory}}</div><div class='head'>คำศัพท์ {level} ที่ควรจำ</div>{{Vocab}}<div class='head'>例文</div>{{Examples}}</div>"
        }],
        css=f""".card{font-family:Arial,'Noto Sans JP',sans-serif;font-size:20px;text-align:center;padding:18px}
.kanji-box{width:190px;height:190px;margin:12px auto;border:4px solid {color};border-radius:18px;display:flex;align-items:center;justify-content:center;font-size:122px;font-weight:700;line-height:1}
.kanji-box.small{width:145px;height:145px;font-size:92px}
.front-meta{font-size:22px;margin-top:14px} .sep{opacity:.55;padding:0 8px}
.jlpt{display:inline-block;margin-top:12px;padding:7px 15px;border-radius:999px;background:{color};color:white;font-weight:700}
.body{text-align:left;line-height:1.65} .head{font-size:23px;font-weight:700;margin-top:22px;margin-bottom:6px}
.memory{margin-top:20px;padding:13px;border-left:5px solid {color};border-radius:8px;background:rgba(128,128,128,.12)}
.tag{display:inline-block;font-size:14px;padding:2px 7px;border-radius:8px;background:rgba(128,128,128,.18)} hr#answer{margin:22px 0}"""
    )

def build(level):
    data=unpack(level) if level in EMBEDDED else fetch_remote(level)
    cfg=CONFIG[level]
    deck=genanki.Deck(cfg["deck_id"],cfg["title"])
    model=make_model(level)
    for item in data:
        deck.add_note(genanki.Note(
            model=model,
            fields=[
                str(item["kanji"]),str(item.get("strokes") or "?"),str(item.get("pos") or "未分類"),
                str(item.get("on") or "—"),str(item.get("kun") or "—"),str(item.get("meaning") or ""),
                str(item.get("memory") or ""),vocab_html(item.get("vocab") or []),examples_html(item.get("examples") or [])
            ],
            tags=[f"JLPT_{level}","Kanji","Thai"]
        ))
    apkg=APKG_DIR/f"JLPT_{level}_Kanji_Thai.apkg"
    genanki.Package(deck).write_to_file(apkg)
    csv_path=CSV_DIR/f"JLPT_{level}_Kanji_Thai.csv"
    with csv_path.open("w",encoding="utf-8",newline="") as f:
        w=csv.writer(f); w.writerow(["Kanji","Stroke","POS","On","Kun","Meaning","Memory","Vocab","Examples"])
        for item in data:
            w.writerow([item["kanji"],item.get("strokes") or "?",item.get("pos") or "未分類",item.get("on") or "—",item.get("kun") or "—",item.get("meaning") or "",item.get("memory") or "",vocab_html(item.get("vocab") or []),examples_html(item.get("examples") or [])])
    print(f"สร้าง {level} สำเร็จ: {len(data)} ใบ")

def main():
    p=argparse.ArgumentParser()
    p.add_argument("--levels",nargs="+",default=["N5","N4","N3","N2","N1"],choices=["N5","N4","N3","N2","N1"])
    args=p.parse_args()
    for level in args.levels:
        build(level)

if __name__=="__main__":
    main()
